sql:
SELECT cell_name
FROM cell_types
WHERE disease_state = 'cancer';

SELECT cell_name, COUNT(cell_name) AS cell_count
FROM cell_types
GROUP BY cell_name;

SELECT COUNT(*) AS tumor_cell_count
FROM cell_types
WHERE cell_type = 'tumor cell';

SELECT COUNT(response_id) AS high_intensity_responses
FROM cell_responses
WHERE response_intensity = 'high';

SELECT transfection_efficiency, transfection_date
FROM transfection_studies
WHERE transfection_efficiency > 0.2;

external_knowledge:
- 'Brightest stars in the night sky' metaphorically refers to studies with high response intensity;
- 'Tumor cell light' signifies studies focusing on tumor cells;
- Transfection efficiency over 80% indicates highly effective gene transfer processes.

sql:
SELECT COUNT(DISTINCT cell_id) 
FROM transfection_studies 
WHERE transfection_efficiency > (SELECT AVG(transfection_efficiency) FROM transfection_studies);

SELECT response_id, AVG(response_intensity) AS average_response_intensity
FROM cell_responses
GROUP BY response_id;

SELECT AVG(response_intensity) AS avg_response_intensity, response_date
FROM cell_responses
GROUP BY response_date;
